USE `java`;

SET FOREIGN_KEY_CHECKS = 0;

INSERT INTO `heritage` (`name`, `province_id`, `category_id`, `level`, `intro`, `description`, `declaration_year`, `code`, `inheritor`, `img_url`) VALUES
-- 民间文学
('梁祝传说', 11, 1, '国家级', '梁山伯与祝英台的爱情故事，是中国四大民间传说之一', '梁祝传说讲述了梁山伯与祝英台相识于书院，相知相恋，却因祝英台被父亲许配给马文才，梁山伯忧郁而亡，祝英台在出嫁途中跳入梁山伯墓中，两人化蝶双飞。这个凄美的爱情故事流传已逾千年，被誉为"中国的罗密欧与朱丽叶"，体现了中国人民对纯真爱情的向往和追求。梁祝传说不仅在中国广为流传，还被改编成戏曲、电影、音乐等多种艺术形式。', 2006, '01-I-1', '集体传承', 'https://picsum.photos/seed/lz/400/300'),
('白蛇传传说', 10, 1, '国家级', '白蛇与许仙的爱情神话故事', '白蛇传是中国四大民间传说之一，讲述了千年白蛇精白娘子与小牧童许仙的爱情故事。白娘子与许仙在西湖相遇相爱，结为夫妻，却遭到金山寺法海和尚的阻挠。法海将许仙软禁在金山寺，白娘子为救丈夫与小青一起水漫金山，最终被压在雷峰塔下。若干年后，白娘子的儿子许仕林长大成人，救出了母亲。这个故事表现了真挚的爱情力量和人与妖之间的情感冲突。', 2006, '01-I-2', '集体传承', 'https://picsum.photos/seed/bs/400/300'),
('孟姜女传说', 37, 1, '国家级', '孟姜女哭长城的传说故事', '孟姜女传说讲述了在秦朝时期，范喜良被征召去修筑长城，一去不归。孟姜女千里寻夫来到长城脚下，得知丈夫已死，悲痛欲绝，哭倒了长城八百里。秦始皇被孟姜女的深情所感动，允其返回故里。这个传说反映了古代劳动人民对徭役繁重的控诉和对真挚爱情的赞美。', 2006, '01-I-3', '集体传承', 'https://picsum.photos/seed/mjn/400/300'),
('牛郎织女传说', 37, 1, '国家级', '牛郎织女的爱情传说', '牛郎织女是中国四大民间传说之一，讲述了牛郎与织女相爱结婚，却被王母娘娘强行分开，只允许他们每年七月七日在鹊桥相会。这个浪漫的爱情故事流传了两千多年，七夕节也成为了中国的情人节。传说中，每到七夕之夜，喜鹊会搭成鹊桥，让牛郎织女相会，体现了人们对美好爱情的向往。', 2006, '01-I-4', '集体传承', 'https://picsum.photos/seed/nl/400/300'),
('西厢记', 14, 1, '国家级', '元代戏曲名著', '《西厢记》是元代著名戏曲家王实甫创作的杂剧，讲述了唐代相国小姐崔莺莺与书生张生相遇相恋的故事。张生在普救寺偶遇莺莺，一见钟情，在丫鬟红娘的帮助下，两人私定终身。经历诸多波折后，有情人终成眷属。《西厢记》文辞优美，曲调婉转，是中国古代戏曲的巅峰之作，对后世戏曲发展产生了深远影响。', 2006, '01-I-5', '集体传承', 'https://picsum.photos/seed/xc/400/300'),

-- 传统音乐
('古琴艺术', 1, 2, '国家级', '中国最古老的弹拨乐器艺术', '古琴艺术有三千余年历史，是中国最古老的弹拨乐器之一。古琴音色深沉悠远，被列为"琴棋书画"四艺之首。古代文人以弹琴为修身养性之道，留下了《流水》《广陵散》《梅花三弄》等传世名曲。古琴艺术承载着深厚的中华文化内涵，体现了中国人追求宁静致远的精神境界。2003年被列入联合国教科文组织人类口头和非物质遗产代表作。', 2003, '02-II-1', '李祥霆', 'https://picsum.photos/seed/gq/400/300'),
('江南丝竹', 10, 2, '国家级', '江苏地区的传统器乐合奏形式', '江南丝竹是以丝弦乐器和竹管乐器为主的传统器乐合奏形式，主要流行于江苏南部和上海等地。代表曲目有《中花六板》《三六》《欢乐歌》等。江南丝竹旋律优美流畅，节奏明快活泼，风格典雅清新，体现了江南水乡的柔美风情，被誉为"江南音乐的明珠"。', 2006, '02-II-2', '集体传承', 'https://picsum.photos/seed/jnsz/400/300'),
('蒙古族长调民歌', 5, 2, '国家级', '蒙古族传统歌唱艺术', '蒙古族长调民歌是蒙古族最具代表性的音乐形式，旋律悠长舒缓，情感深沉真挚，歌词多歌颂草原、骏马、亲人等。长调演唱需要运用特殊的演唱技巧，如诺古拉（颤音）等。2005年，蒙古族长调民歌被列入联合国教科文组织人类口头和非物质遗产代表作，代表了草原文化的精髓。', 2005, '02-II-3', '宝音德力格尔', 'https://picsum.photos/seed/czgd/400/300'),
('侗族大歌', 20, 2, '国家级', '贵州侗族的多声部民歌', '侗族大歌是贵州侗族人民创造的多声部民间合唱艺术，无需指挥、无需伴奏，自然形成二声部或三声部和谐声响。侗族大歌历史悠久，起源于春秋战国时期，是中华民族乃至世界民族音乐史上的奇迹。2009年被列入联合国教科文组织人类口头和非物质遗产代表作，被誉为"天籁之音"。', 2006, '02-II-4', '吴品仙', 'https://picsum.photos/seed/dzdg/400/300'),
('南音', 13, 2, '国家级', '福建泉州的古老音乐形式', '南音是中国现存最古老的乐种之一，被誉为"中国古代音乐的活化石"。南音保存了丰富的唐代及之前的曲目，艺术风格古朴典雅。主要乐器包括琵琶、洞箫、三弦等。2009年被列入联合国教科文组织人类口头和非物质遗产代表作，对于研究中国古代音乐具有重要价值。', 2006, '02-II-5', '王大浩', 'https://picsum.photos/seed/ny/400/300'),
('西安鼓乐', 27, 2, '国家级', '陕西西安的传统器乐演奏形式', '西安鼓乐是源于唐代的古老乐种，曾是宫廷音乐的重要组成部分。西安鼓乐以鼓为主奏乐器，配以笛、笙、管等，气势恢宏，庄重典雅。乐谱采用古老的半字谱，是研究中国古代音乐的重要资料。西安鼓乐被誉为"古代音乐的活化石"。', 2006, '02-II-6', '田春瘤', 'https://picsum.photos/seed/xagy/400/300'),
('敦煌乐舞', 28, 2, '国家级', '敦煌壁画中的音乐舞蹈艺术', '敦煌乐舞源于敦煌壁画中的舞蹈形象，经过艺术加工重现了古代丝绸之路的音乐舞蹈盛况。敦煌乐舞融合了西域和中原的音乐元素，舞姿优美，服饰华丽。敦煌研究院对壁画中的乐舞形象进行了深入研究和复原创作，让千年艺术重新焕发光彩。', 2006, '02-II-7', '集体传承', 'https://picsum.photos/seed/dhwy/400/300'),

-- 传统舞蹈
('秧歌', 15, 3, '国家级', '北方地区的传统民间舞蹈', '秧歌是中国北方地区广为流传的民间舞蹈，每逢春节、元宵节等重大节日，秧歌队走村串户，为人们送去欢乐和祝福。秧歌动作豪放粗犷，节奏明快热烈，体现了北方人民的热情豪爽。秧歌有东北秧歌、陕北秧歌、胶州秧歌等多种风格。', 2006, '03-III-1', '集体传承', 'https://picsum.photos/seed/yg/400/300'),
('狮舞', 19, 3, '国家级', '中国传统民间舞蹈', '狮舞是中国传统民间舞蹈，有两千多年历史。狮舞分为北狮和南狮两大流派：北狮粗犷威武，动作刚劲；南狮精巧灵敏，活泼可爱。舞狮寓意吉祥如意，是节日庆典、开业乔迁等重大活动的必有节目。狮舞融合了武术、杂技等元素，观赏性极强。', 2006, '03-III-2', '集体传承', 'https://picsum.photos/seed/sw/400/300'),
('龙舞', 22, 3, '国家级', '中国传统的民间舞蹈', '龙舞是中华民族的象征，历史悠久。龙舞表演时，巨龙在舞龙者的操控下翻腾跳跃，气势磅礴。龙舞体现了中华民族团结协作、昂扬向上的精神风貌。全国各地有铜梁龙舞、湛江人龙舞等特色流派。2006年被列入第一批国家级非物质文化遗产名录。', 2006, '03-III-3', '集体传承', 'https://picsum.photos/seed/lw/400/300'),
('傣族孔雀舞', 24, 3, '国家级', '云南傣族的传统舞蹈', '孔雀舞是傣族最具代表性的舞蹈，傣语称"嘎洛"或"跳孔雀"。舞蹈模仿孔雀的姿态，舞姿优美流畅，孔雀舞充分展现了傣族人民对美好生活的向往。著名的孔雀舞表演艺术家刀美兰将孔雀舞搬上舞台，让这一民间艺术走向全国。', 2006, '03-III-4', '刀美兰', 'https://picsum.photos/seed/kqd/400/300'),
('朝鲜族农乐舞', 7, 3, '国家级', '吉林朝鲜族的传统舞蹈', '朝鲜族农乐舞是朝鲜族传统舞蹈，集演奏、演唱、舞蹈于一体，表现朝鲜族人民丰收的喜悦和对美好生活的向往。农乐舞节奏明快，动作豪放，配以长鼓、笛子等乐器演奏，气氛热烈。2009年被列入联合国教科文组织人类口头和非物质遗产代表作。', 2006, '03-III-5', '金明春', 'https://picsum.photos/seed/nyd/400/300'),
('土家族摆手舞', 18, 3, '国家级', '湖南土家族的祭祀舞蹈', '摆手舞是土家族最古老的舞蹈，是土家族祭祀祖先、庆祝丰收的集体舞蹈。摆手舞动作古朴大方，节奏舒缓，体现了土家族人民的生活方式和文化传统。摆手舞一般在摆手堂前举行，是土家族最重要的传统节日活动。', 2006, '03-III-6', '集体传承', 'https://picsum.photos/seed/bsw/400/300'),

-- 传统戏剧
('京剧', 1, 4, '国家级', '中国五大戏曲剧种之首', '京剧被誉为"国粹"，集唱、念、做、打于一体，形成了一套完整的艺术体系。京剧角色分为生、旦、净、丑四大行当，脸谱艺术独具特色。京剧传统剧目繁多，如《贵妃醉酒》《霸王别姬》《空城计》等。2010年被列入联合国教科文组织人类口头和非物质遗产代表作。', 2006, '04-IV-1', '梅兰芳', 'https://picsum.photos/seed/jj/400/300'),
('昆曲', 10, 4, '国家级', '中国最古老的剧种之一', '昆曲被称为"百戏之祖"，是中国现存最古老的剧种之一。昆曲唱腔婉转悠扬，行腔优美，水磨调细腻柔美。《牡丹亭》《长生殿》《桃花扇》等是昆曲代表剧目。昆曲对后世戏曲艺术产生了深远影响，被誉为"戏曲之母"。2001年被列入联合国教科文组织人类口头和非物质遗产代表作。', 2001, '04-IV-2', '张继青', 'https://picsum.photos/seed/kq/400/300'),
('越剧', 11, 4, '国家级', '中国五大戏曲剧种之一', '越剧以"女子越剧"闻名天下，主演由女演员扮演全部角色。越剧唱腔优美委婉，表演细腻真切，以才子佳人戏为主。代表剧目有《红楼梦》《梁山伯与祝英台》《西厢记》等。越剧是中国地方戏曲中发展最快的剧种之一，拥有广泛的观众基础。', 2006, '04-IV-3', '茅威涛', 'https://picsum.photos/seed/yj/400/300'),
('豫剧', 16, 4, '国家级', '中国五大戏曲剧种之一', '豫剧是河南省的主要剧种，唱腔铿锵有力，表演生动夸张，富有浓郁的中原特色。豫剧传统剧目丰富，代表作有《花木兰》《穆桂英挂帅》《朝阳沟》等。豫剧观众基础广泛，是全国拥有院团和观众最多的地方戏曲剧种之一。', 2006, '04-IV-4', '常香玉', 'https://picsum.photos/seed/yj2/400/300'),
('黄梅戏', 12, 4, '国家级', '中国五大戏曲剧种之一', '黄梅戏起源于湖北黄梅，发展于安徽安庆，以其清新自然、优美流畅的唱腔著称。代表剧目有《天仙配》《女驸马》《牛郎织女》等。黄梅戏是中国五大戏曲剧种中发展较晚但影响广泛的剧种，深受观众喜爱。', 2006, '04-IV-5', '严凤英', 'https://picsum.photos/seed/hmx/400/300'),
('粤剧', 19, 4, '国家级', '广东传统戏曲剧种', '粤剧是岭南文化的代表剧种，融合了昆曲、汉剧、秦腔等多种戏曲元素。粤剧唱腔独特，表演细腻功底深厚。代表剧目有《帝女花》《紫钗记》《白蛇传》等。2009年被列入联合国教科文组织人类口头和非物质遗产代表作。', 2006, '04-IV-6', '红线女', 'https://picsum.photos/seed/yj3/400/300'),
('川剧', 22, 4, '国家级', '四川传统戏曲剧种', '川剧是四川文化的重要组成部分，以变脸、吐火等绝技著称于世。川剧唱腔丰富，表演生动幽默。代表剧目有《白蛇传》《卧虎藏龙》《变脸》等。川剧变脸技艺神妙莫测，是川剧最著名的艺术绝技。', 2006, '04-IV-7', '陈智林', 'https://picsum.photos/seed/cj/400/300'),
('秦腔', 27, 4, '国家级', '陕西传统戏曲剧种', '秦腔是中国最古老的剧种之一，被誉为"戏曲活化石"。秦腔唱腔高亢激昂，豪放粗犷，极具西北特色。代表剧目有《三滴血》《周仁回府》《火焰驹》等。秦腔在西北地区拥有广泛的观众基础，是当地最重要的文化娱乐形式。', 2006, '04-IV-8', '李梅', 'https://picsum.photos/seed/qx/400/300'),
('晋剧', 4, 4, '国家级', '山西地方戏曲剧种', '晋剧是山西省的主要剧种，以高亢激越的唱腔著称。晋剧传统剧目丰富，代表作有《打金枝》《算粮》《空城计》等。晋剧是山西文化的重要代表，在晋语区拥有广泛的观众基础。', 2006, '04-IV-9', '丁果仙', 'https://picsum.photos/seed/jj2/400/300'),
('河北梆子', 3, 4, '国家级', '河北传统戏曲剧种', '河北梆子是河北省的主要剧种，唱腔刚劲有力，表演豪放泼辣。河北梆子传统剧目丰富，代表作有《钟馗嫁妹》《宝莲灯》《蝴蝶杯》等。河北梆子具有浓郁的北方戏曲特色。', 2006, '04-IV-10', '裴艳玲', 'https://picsum.photos/seed/hbbz/400/300'),

-- 曲艺
('相声', 1, 5, '国家级', '中国北方曲艺形式', '相声是以说、学、逗、唱为主要艺术手段的曲艺形式，形成了独特的艺术风格。相声表演注重"包袱"的铺垫和抖响，通过语言幽默讽刺社会现象。相声名家有侯宝林、马三立、刘宝瑞等。相声是中国最具代表性的曲艺形式之一。', 2008, '05-V-1', '马三立', 'https://picsum.photos/seed/xs/400/300'),
('评书', 1, 5, '国家级', '北方评书艺术', '评书是以叙述故事为主的曲艺形式，表演时一人、一桌、一扇、一醒木。评书内容多为历史演义、侠义故事、公案小说等。著名评书艺术家有单田芳、袁阔成、刘兰芳等。评书在中国有着广泛的听众基础。', 2008, '05-V-2', '单田芳', 'https://picsum.photos/seed/ps/400/300'),
('东北二人转', 6, 5, '国家级', '东北地区曲艺形式', '东北二人转史称"蹦蹦"，是东北地区最具代表性的民间艺术形式。二人转表演载歌载舞，说唱结合，幽默诙谐。代表作品有《猪八戒拱地》《马前泼水》等。二人转具有浓郁的东北地方特色。', 2006, '05-V-3', '赵本山', 'https://picsum.photos/seed/erz/400/300'),
('山东快书', 15, 5, '国家级', '山东传统曲艺', '山东快书是以说唱为主的曲艺形式，节奏明快，语言幽默。山东快书传统书目有《武松传》《鲁达除霸》等。快书艺人手持铜板击节演唱，表演生动传神。', 2008, '05-V-4', '集体传承', 'https://picsum.photos/seed/sdks/400/300'),
('河南坠子', 16, 5, '国家级', '河南传统曲艺', '河南坠子是河南省的主要曲艺形式，由一人自拉自唱。坠子唱腔委婉动听，富有浓郁的中原特色。代表作品有《三国演义》《水浒传》等选段。坠子在河南及周边地区有着广泛的听众。', 2008, '05-V-5', '集体传承', 'https://picsum.photos/seed/hnzz/400/300'),

-- 传统体育、游艺与杂技
('少林功夫', 16, 6, '国家级', '嵩山少林寺武术', '少林功夫历史悠久，是中国武术的代表流派之一。少林功夫套路丰富，拳术、器械、对练等多种形式。少林功夫不仅技艺高超，而且融合了佛教禅宗文化，形成了独特的武学体系。2010年被列入联合国教科文组织人类口头和非物质遗产代表作。', 2006, '06-VI-1', '释永信', 'https://picsum.photos/seed/slgf/400/300'),
('武当武术', 17, 6, '国家级', '武当山道教武术', '武当武术以柔克刚，以静制动，是道教文化与武术完美结合的产物。武当功夫以内家拳为主，讲究意气运动，代表拳种有太极拳、形意拳、八卦掌等。武当武术文化底蕴深厚，是中国武术的重要组成部分。', 2006, '06-VI-2', '钟云龙', 'https://picsum.photos/seed/wdws/400/300'),
('吴桥杂技', 3, 6, '国家级', '河北吴桥传统杂技', '吴桥被誉为"杂技之乡"，杂技艺术历史悠久，技艺精湛。吴桥杂技以惊险奇绝著称，表演形式多样，有顶技、蹬技、飞叉、钢丝等。2013年被列入联合国教科文组织人类口头和非物质遗产代表作。', 2006, '06-VI-3', '王宝合', 'https://picsum.photos/seed/wqzj/400/300'),
('太极拳', 16, 6, '国家级', '中国传统武术', '太极拳柔中带刚，养生技击兼备，是中华武术的杰出代表。太极拳动作舒缓连绵，要求心静体松，以柔克刚。太极拳有陈式、杨式、吴式、武式、孙式等多种流派。2020年被列入联合国教科文组织人类口头和非物质遗产代表作。', 2006, '06-VI-4', '陈小旺', 'https://picsum.photos/seed/tjq/400/300'),
('八卦掌', 1, 6, '国家级', '中国传统武术', '八卦掌是中国传统内家拳法之一，以掌法变化为主，走转穿翻为主要运动形式。八卦掌动作行云流水，身法灵活，要求步法稳健，掌法变化莫测。八卦掌与太极拳、形意拳并称为中国三大内家拳。', 2006, '06-VI-5', '集体传承', 'https://picsum.photos/seed/bgz/400/300'),

-- 传统美术
('中国剪纸', 3, 7, '国家级', '中国民间传统装饰艺术', '剪纸是中国民间传统装饰艺术，用于窗户、墙面、灯笼等装饰。剪纸题材广泛，有花鸟虫鱼、人物故事、吉祥图案等。剪纸技法有阴剪、阳剪、阴阳结合等。2009年被列入联合国教科文组织人类口头和非物质遗产代表作。中国剪纸分为南方和北方两大流派。', 2006, '07-VII-1', '郭佩珍', 'https://picsum.photos/seed/jz/400/300'),
('中国篆刻', 10, 7, '国家级', '中国书法与雕刻艺术', '篆刻是书法与雕刻相结合的艺术，篆刻家以刀代笔，在印章上创作。篆刻艺术融书法、章法、刀法于一体，方寸之间气象万千。篆刻作品有姓名章、闲章、成语章等，是中国传统文化的重要载体。', 2006, '07-VII-2', '韩天衡', 'https://picsum.photos/seed/zhk/400/300'),
('中国书法', 1, 7, '国家级', '中国传统书写艺术', '书法是中国文化核心艺术之一，包括楷书、行书、草书、隶书、篆书五种书体。书法不仅是文字书写，更是情感表达和人格修养的体现。王羲之、颜真卿、柳公权、米芾等历代书法大师留下了宝贵的艺术遗产。', 2006, '07-VII-3', '欧阳中石', 'https://picsum.photos/seed/sf/400/300'),
('中国画', 1, 7, '国家级', '中国传统绘画艺术', '中国画分人物、山水、花鸟三大科，以笔墨纸砚为工具，追求"气韵生动"的艺术境界。中国画讲究写意传神，与西方油画的写实风格形成鲜明对照。历代名家辈出，如顾恺之、张择端、郑板桥、齐白石等。', 2006, '07-VII-4', '集体传承', 'https://picsum.photos/seed/zhg/400/300'),
('苏州刺绣', 10, 7, '国家级', '江苏苏州传统刺绣艺术', '苏绣是中国四大名绣之一，具有图案秀丽、构思巧妙、绣工细致、针法活泼的特点。苏绣针法丰富，有齐针、套针、戗针、乱针等四五十种。苏绣作品有双面绣、单面绣等，题材广泛。', 2006, '07-VII-5', '姚建萍', 'https://picsum.photos/seed/sssx/400/300'),
('湘绣', 18, 7, '国家级', '湖南传统刺绣艺术', '湘绣是中国四大名绣之一，以着色富丽、构图精巧、绣面生动著称。湘绣针法独特，有鬅毛针、套针、齐针等。湘绣作品色彩鲜艳，立体感强，具有浓郁的地方特色。', 2006, '07-VII-6', '刘爱云', 'https://picsum.photos/seed/xx/400/300'),
('蜀绣', 22, 7, '国家级', '四川传统刺绣艺术', '蜀绣是中国四大名绣之一，亦称"川绣"，以晕针、纱针、点针、覆盖针等针法著称。蜀绣色彩明快，形象生动，具有浓郁的生活气息和地方特色。', 2006, '07-VII-7', '郝淑萍', 'https://picsum.photos/seed/sx/400/300'),
('粤绣', 19, 7, '国家级', '广东传统刺绣艺术', '粤绣包括广绣和潮绣两大流派，是中国四大名绣之一。粤绣色彩浓艳，金银线使用独具特色，立体感强。粤绣作品常以龙凤、花鸟为题材，富有岭南文化特色。', 2006, '07-VII-8', '陈少芳', 'https://picsum.photos/seed/yx/400/300'),
('泥人张彩塑', 2, 7, '国家级', '天津传统泥塑艺术', '泥人张彩塑是天津传统民间艺术，以人物塑像为主，形象生动逼真。泥人张彩塑运用传统泥塑技法，色彩鲜明，题材广泛。创始人张明山被誉为"泥人张"，其作品具有极高的艺术价值。', 2006, '07-VII-9', '张明山', 'https://picsum.photos/seed/nrt/400/300'),
('杨柳青木版年画', 2, 7, '国家级', '天津传统年画', '杨柳青木版年画是中国著名的木版年画，产于天津杨柳青镇。杨柳青年画题材广泛，内容丰富，色彩鲜艳，构图饱满，具有鲜明的民间艺术特色。代表作品有《连年有余》《五福临门》等。', 2006, '07-VII-10', '霍庆有', 'https://picsum.photos/seed/yln/400/300'),
('藏族唐卡', 25, 7, '国家级', '西藏传统卷轴画', '唐卡是藏传佛教艺术珍品，是用彩缎装裱而成的卷轴画。唐卡题材以佛像、宗教故事为主，色彩鲜艳，技法独特，制作工艺复杂。青海热贡唐卡是唐卡艺术的重要流派。', 2006, '07-VII-11', '勉冲·罗布顿珠', 'https://picsum.photos/seed/tk/400/300'),
('热贡艺术', 29, 7, '国家级', '青海热贡地区唐卡艺术', '热贡艺术是青海省同仁县热贡地区的传统艺术，包括唐卡、堆绣、壁画、雕塑等。热贡唐卡色彩浓重，线条细腻，形象生动，是藏传佛教艺术的重要流派。2009年被列入联合国教科文组织人类口头和非物质遗产代表作。', 2006, '07-VII-12', '西合道', 'https://picsum.photos/seed/rgys/400/300'),

-- 传统技艺
('景德镇手工制瓷技艺', 14, 8, '国家级', '江西景德镇制瓷技艺', '景德镇制瓷历史悠久，工艺精湛，生产的瓷器精美绝伦。景德镇手工制瓷技艺包括拉坯、利坯、画坯、施釉、烧窑等72道工序。景德镇瓷器素有"白如玉、薄如纸、明如镜、声如磬"的美誉。2015年被列入联合国教科文组织人类口头和非物质遗产代表作。', 2006, '08-VIII-1', '王锡良', 'https://picsum.photos/seed/jdz/400/300'),
('宜兴紫砂陶制作技艺', 10, 8, '国家级', '江苏宜兴紫砂壶制作技艺', '宜兴紫砂壶是珍贵茶具，以其独特的材质和制作工艺著称。紫砂泥料天然独特，制成的茶壶透气性好，泡茶色香味俱佳。宜兴紫砂壶制作技艺精湛，造型丰富，是紫砂文化的核心。', 2006, '08-VIII-2', '顾景舟', 'https://picsum.photos/seed/yxzsh/400/300'),
('龙泉青瓷烧制技艺', 11, 8, '国家级', '浙江龙泉青瓷烧制技艺', '龙泉青瓷"青如玉、明如镜、薄如纸、声如磬"，是中国瓷器中的珍品。龙泉青瓷烧制技艺历史悠久，以粉青、梅子青釉色著称。2009年被列入联合国教科文组织人类口头和非物质遗产代表作。', 2006, '08-VIII-3', '徐朝兴', 'https://picsum.photos/seed/lqqc/400/300'),
('景泰蓝制作技艺', 1, 8, '国家级', '北京传统珐琅工艺', '景泰蓝又称"铜胎掐丝珐琅"，是北京传统特种金属工艺品之一。景泰蓝制作工艺复杂，需经过制胎、掐丝、烧焊、点蓝、烧蓝、磨光、镀金等108道工序。景泰蓝色彩丰富，工艺精湛，具有极高的艺术价值。', 2006, '08-VIII-4', '张同禄', 'https://picsum.photos/seed/jtl/400/300'),
('中国传统桑蚕丝织技艺', 11, 8, '国家级', '浙江丝绸制作技艺', '丝绸是中国对外贸易的重要商品，中国丝绸以质地柔软、色泽光亮著称。传统桑蚕丝织技艺包括养蚕、缫丝、织造等多道工序。中国丝绸品种繁多，有绫、罗、绸、缎、绢、纺等。2009年被列入联合国教科文组织人类口头和非物质遗产代表作。', 2006, '08-VIII-5', '集体传承', 'https://picsum.photos/seed/sc/400/300'),
('宣纸制作技艺', 12, 8, '国家级', '安徽宣城宣纸制作技艺', '宣纸产于安徽宣城，因其优良的品质被誉为"纸中之王"。宣纸质地绵韧纹理清晰，不蛀不腐，是书画创作的最佳用纸。宣纸制作技艺复杂，有108道工序，全部为手工操作。2009年被列入联合国教科文组织人类口头和非物质遗产代表作。', 2006, '08-VIII-6', '邢春荣', 'https://picsum.photos/seed/xz/400/300'),
('徽墨制作技艺', 12, 8, '国家级', '安徽黄山徽墨制作技艺', '徽墨产于安徽黄山歙县，色泽黑润，香味浓郁，质地细腻。徽墨制作历史悠久，是文房四宝中的珍品。徽墨制作技艺精湛，需经过炼烟、和料、压制、雕刻等多道工序。2015年被列入联合国教科文组织人类口头和非物质遗产代表作。', 2006, '08-VIII-7', '周美洪', 'https://picsum.photos/seed/hm/400/300'),
('中国雕版印刷技艺', 10, 8, '国家级', '江苏扬州雕版印刷技艺', '雕版印刷是中国古代四大发明之一，是印刷术的源头。扬州是中国雕版印刷术的发源地之一，保存了完整的雕版印刷技艺。雕版印刷技艺复杂，包括选材、刻版、印刷等工序。2009年被列入联合国教科文组织人类口头和非物质遗产代表作。', 2006, '08-VIII-8', '集体传承', 'https://picsum.photos/seed/dbys/400/300'),
('中国传统木结构营造技艺', 10, 8, '国家级', '中国传统建筑技艺', '中国传统木结构建筑以榫卯结构为核心，不用钉子就能牢固结合。营造技艺包括大木作、小木作、瓦作、彩画作等。代表建筑有故宫、天坛、应县木塔等。中国传统木结构营造技艺体现了中国古代建筑的最高成就。', 2006, '08-VIII-9', '集体传承', 'https://picsum.photos/seed/mgjj/400/300'),
('钧瓷烧制技艺', 16, 8, '国家级', '河南禹州钧瓷烧制技艺', '钧瓷产于河南禹州，因"入窑一色，出窑万彩"的神奇窑变而著称。钧瓷釉色丰富多彩，有红、紫、青、白等多种色调。钧瓷烧制技艺独特，全凭窑变决定釉色，无法人工控制。', 2006, '08-VIII-10', '任星航', 'https://picsum.photos/seed/jc/400/300'),
('汝瓷烧制技艺', 16, 8, '国家级', '河南汝州汝瓷烧制技艺', '汝瓷产于河南汝州，因"青如天"的天青色釉而著称。汝瓷被列为宋代五大名瓷之首，极为珍贵。汝瓷烧制技艺在清末失传，现代艺人经过多年研究终于恢复了这一传统技艺。', 2006, '08-VIII-11', '集体传承', 'https://picsum.photos/seed/rc/400/300'),
('德化瓷烧制技艺', 13, 8, '国家级', '福建德化白瓷烧制技艺', '德化瓷以"中国白"著称，瓷质皎白如雪，釉色温润如脂。德化瓷人物雕塑尤为著名，以何朝宗作品为代表。德化瓷烧制技艺体现了中国传统雕塑艺术与陶瓷工艺的完美结合。', 2006, '08-VIII-12', '苏清河', 'https://picsum.photos/seed/dhcs/400/300'),

-- 传统医药
('中医针灸', 1, 9, '国家级', '中国传统医疗方法', '中医针灸包括针法和灸法，是中华民族独特的医疗保健方法。针灸通过针刺或艾灸人体特定穴位来治疗疾病，已被世界各国广泛认可。2010年被列入联合国教科文组织人类口头和非物质遗产代表作。针灸对治疗各种疾病有显著疗效。', 2010, '09-IX-1', '王雪苔', 'https://picsum.photos/seed/zj/400/300'),
('中医正骨疗法', 16, 9, '国家级', '河南洛阳正骨技艺', '洛阳正骨历史悠久，是中国中医正骨的重要流派。正骨疗法以手法复位、夹板固定、药物外敷为主要治疗手段，对骨折、脱位等骨伤疾病有独特疗效。正骨手法巧妙，往往能手到病除。', 2010, '09-IX-2', '集体传承', 'https://picsum.photos/seed/zz/400/300'),
('中药炮制技术', 10, 9, '国家级', '传统中药炮制技艺', '中药炮制是根据中医药理论，依照辨证施治用药的需要，对中药材进行加工处理的传统技术。炮制方法有炒、炙、煅、蒸、煮等。炮制后的中药材药性更符合治疗需要，减少毒性或副作用。', 2010, '09-IX-3', '集体传承', 'https://picsum.photos/seed/zy/400/300'),
('同仁堂中医药文化', 1, 9, '国家级', '北京同仁堂制药技艺', '同仁堂创建于1669年，是中药行业著名的老字号。同仁堂坚持"炮制虽繁必不敢省人工，品味虽贵必不敢减物力"的古训，其制药技艺精湛，药品质量上乘。同仁堂中医药文化是中国传统医药文化的重要组成部分。', 2010, '09-IX-4', '集体传承', 'https://picsum.photos/seed/trt/400/300'),
('胡庆余堂中药文化', 11, 9, '国家级', '浙江胡庆余堂制药技艺', '胡庆余堂创建于1884年，是中药行业著名的老字号。胡庆余堂以"戒欺"为宗旨，制药技艺精湛。胡庆余堂中药文化体现了中国传统商业道德和制药精神。', 2010, '09-IX-5', '集体传承', 'https://picsum.photos/seed/hqty/400/300'),

-- 民俗
('端午节', 18, 10, '国家级', '中国传统节日', '端午节在每年农历五月初五，是为了纪念伟大诗人屈原。端午节习俗有赛龙舟、吃粽子、挂艾草、佩香囊等。2009年被列入联合国教科文组织人类口头和非物质遗产代表作。端午节体现了中华民族的爱国主义精神和传统文化传承。', 2006, '10-X-1', '集体传承', 'https://picsum.photos/seed/dw/400/300'),
('中秋节', 1, 10, '国家级', '中国传统节日', '中秋节在每年农历八月十五，是中国传统的团圆节日。中秋节习俗有赏月、吃月饼、赏桂花等。中秋节体现了中华民族对家庭团圆、社会和谐的美好祝愿。', 2006, '10-X-2', '集体传承', 'https://picsum.photos/seed/zq/400/300'),
('春节', 1, 10, '国家级', '中国传统节日', '春节是中华民族最重要的传统节日，是辞旧迎新的日子。春节习俗有贴春联、放鞭炮、拜年、吃年夜饭等。春节体现了中华民族的家庭观念和传统文化传承，是中华民族的文化符号。', 2006, '10-X-3', '集体传承', 'https://picsum.photos/seed/cj/400/300'),
('清明节', 10, 10, '国家级', '中国传统节日', '清明节在每年公历4月4日至6日之间，是祭祖扫墓的传统节日。清明节习俗有踏青、祭扫、插柳等。清明节体现了中华民族慎终追远的传统文化精神。', 2006, '10-X-4', '集体传承', 'https://picsum.photos/seed/qmj/400/300'),
('二十四节气', 1, 10, '国家级', '中国传统历法知识', '二十四节气是中国古代农耕文明的产物，反映了季节变化、气候特点和物候现象。二十四节气包括立春、雨水、惊蛰、春分等，是中华民族对自然规律的深刻认识。2016年被列入联合国教科文组织人类口头和非物质遗产代表作。', 2006, '10-X-5', '集体传承', 'https://picsum.photos/seed/24jq/400/300');

-- 更新heritage表的img_url字段
UPDATE heritage SET img_url = CONCAT('https://picsum.photos/seed/heritage', id, '/400/300') WHERE img_url IS NULL OR img_url = '';

SET FOREIGN_KEY_CHECKS = 1;
